package controllers

import play.api.mvc._
import scala.io.Source

object FileController extends Controller {

  def serveFile(filename: String) = Action {
    val safeFilename = sanitizeFilename(filename)
    if (isValidPath(safeFilename)) {
      try {
        val content = Source.fromFile(s"uploads/$safeFilename").mkString
        Ok(content).as("text/plain")
      } catch {
        case e: Exception => NotFound("File not found.")
      }
    } else {
      Forbidden("Invalid file path.")
    }
  }

  private def sanitizeFilename(filename: String): String = {
    filename.replaceAll("[^a-zA-Z0-9._-]", "_")
  }

  private def isValidPath(path: String): Boolean = {
    val basePath = "uploads"
    !path.contains("..") && path.startsWith(basePath)
  }
}